const data = $json.body ?? $json;

const kdNr = String(data.kdNr ?? '').trim();
const auftragsIdRaw = data.auftragsId;
const comment = String(data.comment ?? '').trim();

const auftragsId = Number(auftragsIdRaw);
const patchBodyString = JSON.stringify({ comment });
const signPath = `/customers/${kdNr}/${auftragsId}/comment`;

const inputValid =
  kdNr.length > 0 &&
  Number.isInteger(auftragsId) &&
  auftragsId > 0 &&
  comment.length > 0;

let validationError = null;
let speechText = null;

if (!kdNr) {
  validationError = 'KDNR_MISSING';
  speechText = 'Die Kundennummer fehlt.';
} else if (!Number.isInteger(auftragsId) || auftragsId <= 0) {
  validationError = 'AUFTRAGSID_INVALID';
  speechText = 'Die Auftrags-ID ist ungültig.';
} else if (!comment) {
  validationError = 'COMMENT_MISSING';
  speechText = 'Der Kommentartext fehlt.';
}

return [
  {
    json: {
      kdNr,
      auftragsId,
      comment,
      signPath,
      patchBodyString,
      inputValid,
      validationError,
      speechText,
    },
  },
];

return [
  {
    json: {
      success: false,
      request: {
        kdNr: $json.kdNr || null,
        auftragsId: Number.isInteger($json.auftragsId) ? $json.auftragsId : $json.auftragsId ?? null
      },
      result: null,
      speech: {
        summaryText: $json.speechText || 'Die Anfrage ist ungültig.'
      },
      error: {
        code: $json.validationError || 'VALIDATION_ERROR'
      }
    }
  }
];

return [
  {
    json: {
      success: false,
      request: {
        kdNr: $json.kdNr,
        auftragsId: $json.auftragsId
      },
      result: null,
      speech: {
        summaryText: 'Die Anfrage konnte nicht signiert werden.'
      },
      error: {
        code: 'SIGN_REQUEST_FAILED'
      }
    }
  }
];

const updated = $json.updated === true;
const errorCode = String($json.errorCode ?? '').trim();

const kdNr = $json.kdNr;
const auftragsId = $json.auftragsId;

if (updated) {
  return [
    {
      json: {
        success: true,
        request: {
          kdNr,
          auftragsId,
        },
        result: {
          updated: true,
        },
        speech: {
          summaryText: 'Die Auftragsnotiz wurde erfolgreich gespeichert.',
        },
        error: null,
      },
    },
  ];
}

if (errorCode === 'ORDER_NOT_FOUND') {
  return [
    {
      json: {
        success: false,
        request: {
          kdNr,
          auftragsId,
        },
        result: null,
        speech: {
          summaryText: 'Der Auftrag konnte nicht gefunden werden.',
        },
        error: {
          code: 'ORDER_NOT_FOUND',
        },
      },
    },
  ];
}

if (errorCode === 'ORDER_NOTE_UPDATE_FAILED') {
  return [
    {
      json: {
        success: false,
        request: {
          kdNr,
          auftragsId,
        },
        result: {
          updated: false,
        },
        speech: {
          summaryText: 'Die Auftragsnotiz konnte nicht gespeichert werden.',
        },
        error: {
          code: 'ORDER_NOTE_UPDATE_FAILED',
        },
      },
    },
  ];
}

return [
  {
    json: {
      success: false,
      request: {
        kdNr,
        auftragsId,
      },
      result: null,
      speech: {
        summaryText: 'Die Anfrage konnte nicht verarbeitet werden.',
      },
      error: {
        code: 'UNKNOWN_WORKFLOW_ERROR',
      },
    },
  },
];

const source =
  $json.body && typeof $json.body === 'object'
    ? $json.body
    : $json;

const updated = source.updated === true;
const statusCode = Number($json.statusCode ?? source.statusCode ?? 0);

const errorText = String(
  source.error ??
  $json.error ??
  $json.errorDescription ??
  source.message ??
  $json.message ??
  ''
).trim();

const detailsText = String(
  source.details ??
  $json.details ??
  ''
).trim();

if (updated) {
  return [
    {
      json: {
        updated: true,
        errorCode: null,
        errorMessage: null,
      },
    },
  ];
}

if (
  statusCode === 404 ||
  errorText.includes('Order not found') ||
  detailsText.includes('Order not found')
) {
  return [
    {
      json: {
        updated: false,
        errorCode: 'ORDER_NOT_FOUND',
        errorMessage: 'Der Auftrag konnte nicht gefunden werden.',
      },
    },
  ];
}

return [
  {
    json: {
      updated: false,
      errorCode: 'ORDER_NOTE_UPDATE_FAILED',
      errorMessage: 'Die Auftragsnotiz konnte nicht gespeichert werden.',
    },
  },
];
